void solve(int CASE)
{
	int n; cin >> n;
	if (n == 3 or n == 5) {
		cout << -1 << endl;
		return;
	}

	var ans = vector<int>();
	var add = vector<int>{ 1,2,4,7,10,8,11,12,3,5,9,6 };
	for (int i = 1; i <= n / 12 * 12; i += 12) {
		for (int x : add)ans.pb(i + x - 1);
	}
	var left = vector<int>();
	if (n % 12 == 3 or n % 12 == 5) {
		int cnt = 12;
		while (ans.size() and cnt--)ans.pop_back();

		if (n % 12 == 3)add = vector<int>{ 1,2,4,5,8,10,7,14,6,11,12,3,13,9,15 };
		else add = vector<int>{ 1,2,4,5,8,10,7,14,16,11,6,12,13,3,9,17,15 };

		int now = (n / 12 - 1) * 12 + 1;
		for (int x : add)ans.pb(now + x - 1);
	}
	else {
		fa(i, n / 12 * 12 + 1, n)
			left.pb(i);
	}

	do {
		bool ok = 1;
		if (ans.size()) {
			var tmp = vector<int>{ ans[vs(ans) - 1], ans[vs(ans)] };
			tmp.insert(tmp.end(), all(left));
			fa(i, 0, vs(tmp) - 2) {
				int x = Math::gcd(tmp[i], tmp[i + 1]);
				int y = Math::gcd(tmp[i + 1], tmp[i + 2]);
				int z = Math::gcd(tmp[i], tmp[i + 2]);
				if (x + y + z == 3) {
					ok = 0;
					break;
				}
			}
		}
		else {
			fa(i, 0, vs(left) - 2) {
				int x = Math::gcd(left[i], left[i + 1]);
				int y = Math::gcd(left[i + 1], left[i + 2]);
				int z = Math::gcd(left[i], left[i + 2]);
				if (x + y + z == 3) {
					ok = 0;
					break;
				}
			}
		}
		if (ok) {
			ans.insert(ans.end(), all(left));
			break;
		}
	} while (next_permutation(all(left)));

	cout << ans << endl;

